exercises.starter_code:
class Check:
    registry = {}

    # Implement __init_subclass__ so each subclass is recorded in registry.
    # Support an optional `name=` keyword from the class header.

exercises.solution_code:
class Check:
    registry = {}

    def __init_subclass__(cls, /, name=None, **kwargs):
        super().__init_subclass__(**kwargs)
        key = name if name is not None else cls.__name__
        Check.registry[key] = cls

tests.content:
from solution import Check


def test_base_registry_starts_empty_until_subclassed():
    # The base class itself does not register (only subclasses do).
    assert "Check" not in Check.registry


def test_subclass_registers_under_its_name():
    class PingCheck(Check):
        pass

    assert Check.registry.get("PingCheck") is PingCheck


def test_explicit_name_keyword_overrides_class_name():
    # __init_subclass__ receives keyword arguments passed in the class header.
    class DiskCheck(Check, name="disk"):
        pass

    assert Check.registry.get("disk") is DiskCheck
    assert "DiskCheck" not in Check.registry


def test_multiple_subclasses_all_registered():
    class AlphaCheck(Check):
        pass

    class BetaCheck(Check, name="beta"):
        pass

    assert Check.registry.get("AlphaCheck") is AlphaCheck
    assert Check.registry.get("beta") is BetaCheck


def test_registration_happens_at_definition_not_instantiation():
    # Tricky: the hook fires when the subclass is *defined*, with no instance
    # created. A registry keyed off __init__ would miss never-instantiated
    # classes -- exactly the bug __init_subclass__ avoids.
    created_instances = []

    class TraceCheck(Check):
        def __init__(self):
            created_instances.append(self)

    assert Check.registry.get("TraceCheck") is TraceCheck
    assert created_instances == []

