exercises.solution_code:
class PluginMeta(type):
    def __init__(cls, name, bases, namespace, **kwargs):
        super().__init__(name, bases, namespace, **kwargs)
        # Skip the root class (it has no base built by this metaclass); every
        # descendant has at least one such base, so only descendants register.
        if not any(isinstance(base, PluginMeta) for base in bases):
            return
        cls.registry[name] = cls


class Plugin(metaclass=PluginMeta):
    registry = {}

tests.content:
from solution import Plugin, PluginMeta


def test_metaclass_is_a_subclass_of_type():
    # A metaclass is a class whose instances are themselves classes; it must
    # derive from type.
    assert issubclass(PluginMeta, type)


def test_plugin_class_is_an_instance_of_the_metaclass():
    assert isinstance(Plugin, PluginMeta)


def test_base_does_not_register_itself():
    assert "Plugin" not in Plugin.registry


def test_subclass_is_registered():
    class HttpPlugin(Plugin):
        pass

    assert Plugin.registry.get("HttpPlugin") is HttpPlugin


def test_grandchild_is_also_registered():
    class HttpPlugin(Plugin):
        pass

    class JsonPlugin(HttpPlugin):
        pass

    assert Plugin.registry.get("JsonPlugin") is JsonPlugin


def test_registration_needs_no_instance():
    # Tricky: like __init_subclass__, a class-creation metaclass hook fires at
    # definition time. No instance of the plugin is ever made here.
    class SilentPlugin(Plugin):
        pass

    assert Plugin.registry.get("SilentPlugin") is SilentPlugin

exercises.starter_code:
class ScenarioError(Exception):
    pass


class Scenario:
    registry = {}

    # Implement __init_subclass__:
    #  - require a class attribute `case_id` (else raise ScenarioError)
    #  - reject a duplicate case_id (raise ScenarioError)
    #  - otherwise register the subclass under its case_id

exercises.solution_code:
class ScenarioError(Exception):
    pass


class Scenario:
    registry = {}

    def __init_subclass__(cls, /, **kwargs):
        super().__init_subclass__(**kwargs)
        case_id = getattr(cls, "case_id", None)
        if case_id is None:
            raise ScenarioError(
                f"{cls.__name__} must define a class attribute 'case_id'"
            )
        if case_id in Scenario.registry:
            raise ScenarioError(f"duplicate case_id: {case_id!r}")
        Scenario.registry[case_id] = cls

tests.content:
import pytest

from solution import Scenario, ScenarioError


def test_valid_subclass_registers_by_case_id():
    class LoginScenario(Scenario):
        case_id = "login-001"

    assert Scenario.registry.get("login-001") is LoginScenario


def test_missing_case_id_raises_at_definition():
    # Edge: a subclass without case_id must fail loudly when defined.
    with pytest.raises(ScenarioError):

        class Broken(Scenario):
            pass


def test_missing_case_id_does_not_pollute_registry():
    before = dict(Scenario.registry)
    with pytest.raises(ScenarioError):

        class AlsoBroken(Scenario):
            pass

    assert Scenario.registry == before


def test_duplicate_case_id_is_rejected():
    # Tricky: two scenarios claiming the same id is a real AQA bug (one test
    # silently shadows another). The registry must refuse it.
    class FirstScenario(Scenario):
        case_id = "dup-007"

    with pytest.raises(ScenarioError):

        class SecondScenario(Scenario):
            case_id = "dup-007"

    assert Scenario.registry["dup-007"] is FirstScenario


def test_several_distinct_scenarios_coexist():
    class AlphaScenario(Scenario):
        case_id = "alpha"

    class BetaScenario(Scenario):
        case_id = "beta"

    assert Scenario.registry["alpha"] is AlphaScenario
    assert Scenario.registry["beta"] is BetaScenario
